export const 衝命玉符 = (bi) => {
    const u = bi.u, k = 2.1, cx0 = -7.15, z00 = 7.0;
    const X = (x) => (x - cx0) * k;
    const Z = (z) => (z - z00) * k + 2;
    const 抖 = (書, 寬 = 0.62) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '出' }, 書);
    bi.硃(() => {
        // 頂雙小鉤（左引）
        抖(p => p.M(X(-9.8), Z(8.4))
            .C(X(-9.3), Z(7.9), X(-8.8), Z(8.0), X(-8.5), Z(8.5)), 0.55);
        抖(p => p.M(X(-8.2), Z(9.0))
            .C(X(-7.7), Z(8.5), X(-7.2), Z(8.6), X(-6.9), Z(9.1)), 0.55);
        // 蛇身七折：自右肩尖入，左瀑漸廣
        抖(p => p.M(X(-4.4), Z(7.2))
            .C(X(-5.4), Z(8.0), X(-5.0), Z(9.2), X(-5.6), Z(10.2))
            .C(X(-6.4), Z(11.4), X(-5.2), Z(12.0), X(-5.8), Z(13.2))
            .C(X(-6.6), Z(14.6), X(-8.0), Z(14.2), X(-8.6), Z(15.4))
            .C(X(-9.4), Z(16.8), X(-7.8), Z(17.4), X(-8.4), Z(18.8))
            .C(X(-9.2), Z(20.4), X(-11.0), Z(19.8), X(-10.8), Z(21.4))
            .C(X(-10.6), Z(22.8), X(-9.2), Z(22.6), X(-9.8), Z(24.0))
            .C(X(-10.4), Z(25.1), X(-11.1), Z(25.6), X(-11.7), Z(25.95)), 0.8);
        // 伴行副線：主蛇右側同行一段
        抖(p => p.M(X(-3.8), Z(9.4))
            .C(X(-4.6), Z(10.6), X(-3.9), Z(11.8), X(-4.7), Z(13.0))
            .C(X(-5.5), Z(14.2), X(-4.5), Z(15.2), X(-5.2), Z(16.4))
            .C(X(-5.8), Z(17.4), X(-6.6), Z(18.0), X(-7.2), Z(18.4)), 0.6);
        // 右下短剔
        抖(p => p.M(X(-4.8), Z(24.4))
            .C(X(-4.2), Z(24.9), X(-3.8), Z(25.3), X(-3.5), Z(25.6)), 0.55);
    });
};
